<template><div class="page-content"><PageHeader eyebrow="Release center" title="Releases" description="跨应用统一追踪发布、回滚与环境变更"><el-button @click="load" :loading="loading">刷新</el-button></PageHeader><div class="metrics"><MetricCard title="发布总数" :value="total" icon="↗"/><MetricCard title="成功" :value="successCount" icon="✓" tone="green"/><MetricCard title="失败" :value="failedCount" icon="!" tone="red"/><MetricCard title="Production" :value="prodCount" icon="◆" tone="blue"/></div><section class="surface table-card"><div class="toolbar"><div><el-select v-model="environment" style="width:130px"><el-option label="全部环境" value=""/><el-option v-for="e in ['dev','test','staging','prod']" :key="e" :label="e.toUpperCase()" :value="e"/></el-select><el-select v-model="status" style="width:130px"><el-option label="全部状态" value=""/><el-option v-for="s in ['Succeeded','Failed','Running','Pending']" :key="s" :label="s" :value="s"/></el-select></div><span>{{total}} release records</span></div><el-skeleton :loading="loading" animated :rows="7"><el-table v-if="items.length" :data="items"><el-table-column label="Release" width="90"><template #default="{row}">#{{row.id}}</template></el-table-column><el-table-column label="Image" min-width="260"><template #default="{row}"><code>{{row.image}}</code><small>{{row.git_commit?.slice(0,8)||row.git_branch}}</small></template></el-table-column><el-table-column label="Environment" width="110"><template #default="{row}"><span class="env">{{row.environment}}</span></template></el-table-column><el-table-column label="Type" prop="release_type" width="100"/><el-table-column label="User" prop="deploy_user" width="120"/><el-table-column label="Status" width="120"><template #default="{row}"><StatusBadge :status="row.deploy_status"/></template></el-table-column><el-table-column label="Created" width="170"><template #default="{row}">{{format(row.created_at)}}</template></el-table-column><el-table-column label="操作" width="100"><template #default="{row}"><el-button v-if="row.pipeline_run_name" link @click="$router.push(`/pipelines/${row.pipeline_run_name}`)">日志</el-button></template></el-table-column></el-table><EmptyState v-else title="没有发布记录" description="发布应用后，记录会出现在统一发布中心。"/></el-skeleton><footer><el-pagination v-model:current-page="page" :page-size="pageSize" layout="prev,pager,next" :total="total"/></footer></section></div></template>
<script setup lang="ts">import{computed,onMounted,ref,watch}from'vue';import{releaseApi}from'../api/release';import type{Release}from'../types';import PageHeader from'../components/common/PageHeader.vue';import MetricCard from'../components/common/MetricCard.vue';import StatusBadge from'../components/common/StatusBadge.vue';import EmptyState from'../components/common/EmptyState.vue';const items=ref<Release[]>([]),total=ref(0),page=ref(1),pageSize=20,environment=ref(''),status=ref(''),loading=ref(false);const successCount=computed(()=>items.value.filter(i=>i.deploy_status==='Succeeded').length),failedCount=computed(()=>items.value.filter(i=>i.deploy_status==='Failed').length),prodCount=computed(()=>items.value.filter(i=>i.environment==='prod').length);async function load(){loading.value=true;try{const data=await releaseApi.list({page:page.value,pageSize,environment:environment.value,status:status.value});items.value=data.items;total.value=data.total}finally{loading.value=false}}const format=(v:string)=>new Date(v).toLocaleString('zh-CN',{hour12:false});watch([page,environment,status],()=>{if(environment.value||status.value)page.value=1;load()});onMounted(load)
</script>
<style scoped>.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:14px}.table-card{overflow:hidden}.toolbar{height:58px;padding:0 16px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--border-soft)}.toolbar>div{display:flex;gap:8px}.toolbar>span{font-size:12px;color:var(--muted)}code,small{display:block}code{font-size:13px;color:#a9b2c1}small{font-size:12px;color:var(--muted);margin-top:5px}.env{font-size:12px;text-transform:uppercase;padding:4px 7px;border:1px solid #323847;border-radius:5px}footer{display:flex;justify-content:flex-end;padding:12px 16px;border-top:1px solid var(--border-soft)}</style>
